SELECT(SUM(?numGames) AS ?totalGames) WHERE {
  VALUES ?seriesLabel {
    "1982 National League Championship Series" @en "2006 National League Championship Series" @en "2011 World Series" @en "2013 National League Championship Series" @en "2011 National League Championship Series" @en
  }
  ?series rdfs:label ?seriesLabel .
  ?series wdt:P710 wd:Q166474 .
  ?series wdt:P2633 ?numGames .
}

SELECT ?game ?attendance ?duration WHERE {
  VALUES ?yr {
    1977 1978 2008 2009
  }
  ?series wdt:P31 wd:Q1363275 ; wdt:P585 ?seriesDate .
  ?game wdt:P361 ?series ; wdt:P710 wd:Q334634 ; wdt:P710 wd:Q650840 ; wdt:P1126 ?attendance ; wdt:P2047 ?duration .
  FILTER(YEAR(?seriesDate) = ?yr)
}
ORDER BY ?duration

SELECT ?opponent(MIN(YEAR(?endTime)) AS ?firstYear) WHERE {
  ?season wdt:P31 wd:Q47258137 .
  ?season wdt:P582 ?endTime .
  {
    ?season wdt:P1346 wd:Q249679 .
    ?season wdt:P1347 ?opponent .
  } UNION {
    ?season wdt:P1347 wd:Q249679 .
    ?season wdt:P1346 ?opponent .
  }
  FILTER(?opponent != wd:Q249679)
}
GROUP BY ?opponent
ORDER BY ?firstYear
OFFSET 3
LIMIT 1

