SELECT(COUNT(?game) AS ?count) WHERE {
  VALUES ?year {
    1977 1978 2008 2009
  }
  wd:Q334634 wdt:P1344 ?series .
  wd:Q650840 wdt:P1344 ?series .
  ?series wdt:P585 ?date .
  BIND(YEAR(?date) AS ?yearFiltered)
  FILTER(?yearFiltered = ?year)
  ?game wdt:P361 ?series .
  ?game wdt:P1110 ?attendance .
  FILTER(STRDT(STRBEFORE(?attendance , '.') , xsd:integer) > 50000)
}

SELECT ?totalMinutes WHERE {
  {
    ?game wdt:P1444 wd:Q334634 .
    ?game wdt:P1445 wd:Q650840
  } UNION {
    ?game wdt:P1444 wd:Q650840 .
    ?game wdt:P1445 wd:Q334634
  }
  .
  ?game wdt:P2047 ?duration .
  BIND((COALESCE(REPLACE(?duration , '.*T([0-9]+)H.*' , '$1' , 'i') , 0) * 60 + COALESCE(REPLACE(?duration , '.*T([0-9]+)M.*' , '$1' , 'i') , 0)) AS ?totalMinutes)
}
ORDER BY ?totalMinutes
OFFSET 2
LIMIT 1

