SELECT((COALESCE(?stKildaCount , 0) + COALESCE(?essendonCount , 0) + COALESCE(?richmondCount , 0)) - COALESCE(?collingwoodCount , 0) AS ?difference) WHERE {
  {
    SELECT(COUNT(*) AS ?stKildaCount) WHERE {
      ?season wdt:P1346 wd:Q1084121 .
      ?season wdt:P31 / wdt:P279 * wd:Q19840852 .
    }
  }
  {
    SELECT(COUNT(*) AS ?essendonCount) WHERE {
      ?season wdt:P1346 wd:Q251090 .
      ?season wdt:P31 / wdt:P279 * wd:Q19840852 .
    }
  }
  {
    SELECT(COUNT(*) AS ?richmondCount) WHERE {
      ?season wdt:P1346 wd:Q2521385 .
      ?season wdt:P31 / wdt:P279 * wd:Q19840852 .
    }
  }
  {
    SELECT(COUNT(*) AS ?collingwoodCount) WHERE {
      ?season wdt:P1346 wd:Q249679 .
      ?season wdt:P31 / wdt:P279 * wd:Q19840852 .
    }
  }
}

SELECT((MAX(?count) - MIN(?count)) AS ?difference) WHERE {
  {
    SELECT ?year(COUNT(*) AS ?count) WHERE {
      ?race wdt:P31 wd:Q129237 .
      ?race p:P1346 ?statement .
      ?statement ps:P1346 wd:Q9673 .
      ?statement pq:P54 wd:Q25761776 .
      ?race wdt:P585 ?date .
      BIND(xsd:integer(SUBSTR(STR(?date) , 1 , 4)) AS ?year)
      FILTER(?year > 2015)
    }
    GROUP BY ?year
  }
}

SELECT(SUM(?dodgersWins) AS ?totalWins) WHERE {
  VALUES ?series {
    wd:Q1004352 wd:Q1004228 wd:Q3511262 wd:Q3511261
  }
  ?series wdt:P1346 ?winner ; wdt:P5504 ?games .
  BIND(IF(?series IN(wd:Q1004352 , wd:Q1004228) , 3 , 4) AS ?requiredWins)
  BIND(IF(?winner = wd:Q334634 , ?requiredWins , ?games - ?requiredWins) AS ?dodgersWins)
}

